// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{})
}

type ChiServerOptions struct {
	BaseURL          string
	BaseRouter       chi.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r chi.Router) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r chi.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, ChiServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options ChiServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = chi.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/crt_stores", wrapper.GetCrtStores)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/crt_stores", wrapper.CreateCrtStore)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/crt_stores/{crt_store}/crt_loads", wrapper.GetCrtLoads)
	})
	r.Group(func(r chi.Router) {
		r.Post(options.BaseURL+"/services/haproxy/configuration/crt_stores/{crt_store}/crt_loads", wrapper.CreateCrtLoad)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/crt_stores/{crt_store}/crt_loads/{certificate}", wrapper.DeleteCrtLoad)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/crt_stores/{crt_store}/crt_loads/{certificate}", wrapper.GetCrtLoad)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/crt_stores/{crt_store}/crt_loads/{certificate}", wrapper.ReplaceCrtLoad)
	})
	r.Group(func(r chi.Router) {
		r.Delete(options.BaseURL+"/services/haproxy/configuration/crt_stores/{name}", wrapper.DeleteCrtStore)
	})
	r.Group(func(r chi.Router) {
		r.Get(options.BaseURL+"/services/haproxy/configuration/crt_stores/{name}", wrapper.GetCrtStore)
	})
	r.Group(func(r chi.Router) {
		r.Put(options.BaseURL+"/services/haproxy/configuration/crt_stores/{name}", wrapper.EditCrtStore)
	})

	return r
}

